// src/components/LoginModal.js
import React from 'react';
import '../style/Login.css'; // Re-use your existing auth styles!

const LoginModal = ({ isOpen }) => {
  if (!isOpen) return null;

  return (
    <div className="modal-overlay">
      <div className="auth-card modal-card">
        <div className="auth-header">
          <h2>Sign In to Continue</h2>
          <p>You need an account to access this page</p>
        </div>
        {/* Your existing Login Form logic goes here */}
        <form className="auth-form">
           <div className="input-group">
            <label>Email Address</label>
            <input type="email" placeholder="e.g. name@example.com" />
          </div>
          <button className="auth-btn">Login</button>
        </form>
      </div>
    </div>
  );
};

export default LoginModal;
